// Função para traduzir os valores de triggerEvent
function translateTriggerEvent(event) {
    const translations = {
        "BOOKING_CREATED": "Agendamento",
        "BOOKING_RESCHEDULED": "Reagendamento",
        "BOOKING_CANCELLED": "Cancelamento",
        "MEETING_ENDED": "Reunião finalizada",
        "BOOKING_REJECTED": "Reunião rejeitada",
        "BOOKING_REQUESTED": "Reunião requisitada",
        "MEETING_STARTED": "Reunião iniciada",
        "RECORDING_READY": "Gravação iniciada",
        "FORM_SUBMITTED": "Formulário enviado"
    };

    // Retorna a tradução ou "Desconhecido" se não houver correspondência
    return translations[event] || "Desconhecido";
}

// Traduz o triggerEvent
const translatedTriggerEvent = translateTriggerEvent(triggerEvent);

function capitalizeName(fullName) {
    if (typeof fullName === 'undefined' || !fullName) {
        return { fname: '', lname: '', fullname: '' };
    }

    const lowerCaseWords = ['da', 'de', 'do', 'di', 'du'];
    let words = fullName.toLowerCase().split(' ').map((word, index) => {
        if (lowerCaseWords.includes(word) && index !== 0) {
            return word;
        }
        return word.charAt(0).toUpperCase() + word.slice(1);
    });

    let fname = words.shift();
    let lname = words.join(' ');

    let fullname = lname ? `${fname} ${lname}` : fname;

    return { fname, lname, fullname };
}

function formatEmail(email) {
    if (!email) return "";
    return email.toLowerCase().trim();
}

let telefoneFinal = "";

if (telefoneClienteOriginal) {
    const telefoneLimpo = telefoneClienteOriginal.replace(/\D/g, "");

    let DDI = '';
    let DDD = '';
    let numero = '';

    if (telefoneLimpo.length > 11) {
        DDI = telefoneLimpo.slice(0, 2);
        DDD = telefoneLimpo.slice(2, 4);
        numero = telefoneLimpo.slice(4);
    } else if (telefoneLimpo.length === 11) {
        DDI = '55';
        DDD = telefoneLimpo.slice(0, 2);
        numero = telefoneLimpo.slice(2);
    } else if (telefoneLimpo.length === 10) {
        DDI = '55';
        DDD = telefoneLimpo.slice(0, 2);
        numero = telefoneLimpo.slice(2);
    } else {
        telefoneFinal = telefoneLimpo;
    }

    if (DDD && numero) {
        if (parseInt(DDD) > 28) {
            if (numero.length === 9 && numero.startsWith("9")) {
                numero = numero.slice(1);
            }
        } else {
            if (numero.length === 8) {
                numero = `9${numero}`;
            }
        }
    }

    if (DDI && DDD && numero) {
        telefoneFinal = `${DDI}${DDD}${numero}`;
    }
}

