// Função para formatar a data
function formatToBrazilTime(isoDate) {
    if (!isoDate) return "";

    const date = new Date(isoDate);

    // Formata para o padrão YYYY-MM-DD HH:mm:ss
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    const hours = String(date.getHours()).padStart(2, '0');
    const minutes = String(date.getMinutes()).padStart(2, '0');
    const seconds = String(date.getSeconds()).padStart(2, '0');

    return `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`;
}

// Formata as datas
const formattedEndTime = formatToBrazilTime(endTime);
const formattedStartTime = formatToBrazilTime(startTime);
const formattedCreatedAt = formatToBrazilTime(createdAt);

function obterDiaSemana(dataISO) {
    if (!dataISO) return "";

    const diasDaSemana = ['Domingo', 'Segunda-feira', 'Terça-feira', 'Quarta-feira', 'Quinta-feira', 'Sexta-feira', 'Sábado'];

    const dataObj = new Date(dataISO);
    const indiceDia = dataObj.getUTCDay();

    return diasDaSemana[indiceDia];
}

