return linhasProximas.map(linha => ({ json: linha.json }));

const agora = new Date(); // horário atual
agora.setHours(agora.getHours() - 3); // ajustar para o fuso horário do Brasil (UTC-3)

// Filtrar diretamente sem uso desnecessário de batching
return items.filter(item => {
  // Extrair hora e minuto do horário de início
  const [hora, minuto] = item.json['HORA DE INÍCIO'].split(':');

  // Criar data para o horário de início
  const horaInicio = new Date();
  horaInicio.setHours(hora, minuto);

  // Calcular diferença em minutos
  const diferenca = (horaInicio - agora) / 60000;

  // Retornar apenas os que estão entre 55 e 65 minutos (aproximadamente 1 hora)
  return diferenca >= 55 && diferenca <= 65;
}).map(item => ({ json: item.json }));
